GUI.CommonCode:
/* File version = "2.3" */

/* History:
   2.0 - Add trace to monitor language resolving (2025/06/09).
   2.1 - Add divStepUpAuthorization and lblStepUpAuthorization to JsSetFeatureValue function (2025/06/10).
   2.2 - Add divJustificationTypeArea elements EPM-57766 (2025/11/04)
   2.3 - Fix setting default value for DefaultJustificationHoursLimit EPM-58726 (2025/11/13)
*/

/// <summary>
/// List of Buttons defined for this dialog.
/// </summary>
var EButtons =  
{ 
OK      : 1, 
Cancel  : 2,
StopNow : 3    
} 

var ETraceLevel =  
{ 
DEBUG : 2, 
INFO  : 3,
WARNING: 4, 
ERROR: 5
} 

var InitTimeout    = 30;
var Timeout        = 30;             // in seconds
var ActionButton   = EButtons.OK;    // Button which will be "clicked" automatically when timeout will be expired but no user action taken.
var TimerId        = -1;

var btnOKText      = "";
var btnCancelText  = "";
var btnStopNowText = "";

if (typeof(chrome) != "undefined" && chrome != null && chrome.webview != null && chrome.webview.hostObjects != null && chrome.webview.hostObjects.sync.external != null)
{
    external = chrome.webview.hostObjects.sync.external;
}

function JsGetVersion()
{
/// <summary>
/// V.1 - Script supports JsOnDocumentReady so host must wait for this call (instead of perform some tasks in WebBrowser's DocumentComplete event).
/// </summary>

return 2;
}

function gup(name)
{
name = name.replace(/[\[]/, "\\\[").replace(/[\]]/, "\\\]");
var regexS = "[\\?&]" + name + "=([^&#]*)";
var regex = new RegExp(regexS);
var results = regex.exec(window.location.href);
if (results == null)
return "";
else
return results[1];
}

function substituteVars(ctrlIds)
{
/// <summary>
/// Substitues variables in inner HTML of given controls with real values requested from caller.
/// </suumary>
/// <param name="ctrlIds" type="Array">List of control Id's to process</param>
/// <returns>Nothing</returns>

var vars = new Array(); // All variables required by this page.

// Get list of all variables required by this page.

for (var i = 0; i < ctrlIds.length; i++)
{
var ctrl = document.getElementById(ctrlIds[i]);
if (ctrl == null)
continue;

var isCtrlVisible = ctrl.style.display == null || 
                            ctrl.style.display == ""   || 
                            ctrl.style.display == "block";

        if ((!isCtrlVisible) && (ctrlIds[i] != "lblUserName"))
            continue;

var text = "";
if (ctrl.tagName.toLowerCase() == "input" && typeof(ctrl.value) != "undefined")
text = ctrl.value;
else
text = ctrl.innerHTML;

text = text.replace(/&lt;/g, "<").replace(/&gt;/g, ">");

var x = null;
var regex = new RegExp("(?=<\\$VF_)(.*?)>", "g");
do 
{
x = regex.exec(text);

if (x != null)
{
var varName = x[0];

vars[varName] = varName;
}

} while (x != null)
}

// Get values of all variables.

for (var varName in vars)
{
try
{
var val = null;
if (varName == "<$VF_REQUEST_ID>")
val = OnGetVariableRequestId();
else
val = external.JsOnGetVariable(varName);

vars[varName] = val;
}
catch(ex)
{
vars[varName] = varName;
}
}

// Substitute values instead of variable names.

for (var i = 0; i < ctrlIds.length; i++)
{
var ctrl = document.getElementById(ctrlIds[i]);
if (ctrl == null)
continue;

var text = "";
if (ctrl.tagName.toLowerCase() == "input" && typeof(ctrl.value) != "undefined")
text = ctrl.value;
else
text = ctrl.innerHTML;

text = text.replace(/&lt;/g, "<").replace(/&gt;/g, ">");

for (var varName in vars)
{
var val = vars[varName];

var regex = new RegExp(varName.replace("$", "\\$"), "g");

text = text.replace(regex, val);
}

if (ctrl.tagName.toLowerCase() == "input" && typeof(ctrl.value) != "undefined")
{
ctrl.value = text;
}
else
{
text = fitLine(ctrl, text);
ctrl.innerHTML = text;
}
}

// Notify host about completing

try
{
external.JsOnDocumentReady();
}
catch (ex) { }
}

function getTimeout(defaultTimeout)
{
try
{
var inp = document.getElementById("DialogTimeout");
if (inp != null)
return parseInt(inp.value, /* radix = */ 10);
else
return defaultTimeout;
}
catch(ex)
{
return defaultTimeout;
}
}

function showTimeout(customWidth)
{
var actionButton = null;
var buttonText   = "";

switch (ActionButton)
{
case EButtons.OK:       
actionButton = document.getElementById("btnOK");        
buttonText   = btnOKText;
break;

case EButtons.Cancel:   
actionButton = document.getElementById("btnCancel");    
buttonText   = btnCancelText;
break;

case EButtons.StopNow:   
actionButton = document.getElementById("btnStopNow");    
buttonText   = btnStopNowText;
break;
}

if (actionButton != null)
{
var text = buttonText;

if (Timeout <= 10)
{
if (typeof customWidth !== 'undefined')
actionButton.style.width = customWidth + 'px';

text = buttonText + " (" + Timeout + ")";
}

var tagName = actionButton.tagName.toLowerCase();

if (tagName == "input")
actionButton.value = text;
else if (tagName == "button")
actionButton.innerHTML = text;
}

// Notify external host about timeout progress
try
{
external.JsOnProgressTimeout(Timeout);
}
catch(ex) { }

if (--Timeout >= 0)  
{
if (typeof customWidth !== 'undefined')
TimerId = setTimeout(function() { showTimeout(customWidth); }, 1000);
else
TimerId = setTimeout(function() { showTimeout(); }, 1000);
}
else
{
if (actionButton != null && typeof(actionButton.click) != "undefined")
{
actionButton.click();
}
}
}

function resetTimeout()
{
Timeout = InitTimeout;    

try
{
external.JsOnResetTimeout();
}   
catch(ex) { }     
}

function stopTimeout()
{       
try
{
if (TimerId != -1)
{
clearTimeout(TimerId);
TimerId = -1;
}
}
catch(ex) { }
}

function IsPreviewMode()
{
var isPreviewMode = false;
try
{
if (external != null)
isPreviewMode = external.JsIsPreviewMode();
else
isPreviewMode = true;   // "external" still not initialized; for more security behave as in Preview (i.e.without scripts).
}
catch(ex) 
{ 
}

return isPreviewMode;
}

function InitJustificationArea()
{
try
{
if (JsIsFeatureEnabled("divJustificationArea"))
{
var options = document.getElementsByName("optJustificationOption");

var isChecked = false;
var isVisible = false;

for (var i = 0; i < options.length; i++)
{
var opt = options[i];
if (opt != null)
{
var isOptVisible = opt.style.display == null || 
                                       opt.style.display == ""   || 
                                       opt.style.display == "block";

if (isOptVisible)
{
opt.checked = true;
isChecked   = true;
isVisible   = true;
onJustificationOptionClick(opt.id);
break;
}
}
}

if (!isVisible)
{
// When no option is visible, but entire feature is enabled 
// suppose that only txtJustification textarea appears on the dialog.
onJustificationOptionClick("optJustificationManual");
}
}
}
catch(ex) {}
}

function onJustificationOptionClick(optId)
{
try
{
var opt = document.getElementById(optId);
if (opt != null)
opt.blur();

var txtJustification = document.getElementById("txtJustification");
if (txtJustification != null)
{
if (optId == "optJustificationManual")
{
txtJustification.disabled = false;
txtJustification.focus();   
}
else
{
txtJustification.disabled = true;
}
}

}
catch(ex) 
{ 
}
}

function validateJustification()
{
/// <summary>
/// Returns "false" when "txtJustification" is visible but not completed by user.
/// Otherwise "true" is returned.
/// </summary>

try
{
if (!JsIsFeatureEnabled("divJustificationArea"))
return true;    // Entire Justification feature is disable.

// Check by flag whether we need to perform validation.
var needValidateJustification = true;
var inp = document.getElementById("NeedValidateJustification");
if (inp != null && inp.value != null)
needValidateJustification = inp.value.toLowerCase() == "true" || inp.value == "1";  
if (!needValidateJustification)
return true;

// Check whether one of visible options is checked
var visibleOptionExists = false;
var checkedOption = null;
var options = document.getElementsByName("optJustificationOption");
for (var i = 0; i < options.length; i++)
{
var opt = options[i];
if (opt == null)
continue;

if (opt.style.display == "none")
continue;

visibleOptionExists = true;

if (opt.checked)
{
checkedOption = opt; 
break;
}   
}

if (!visibleOptionExists)
{
// Even when no visible option exists, txtJustification itself can be visible.
var txtJustification = document.getElementById("txtJustification");
if (txtJustification == null || txtJustification.style.display == "none")
return true;                // No visible option exists => justification should not be provided.
else
checkedOption = document.getElementById("optJustificationManual");
}

if (checkedOption == null)      // Visible option exists but no one is checked by user.
{
MsgBoxError("One of option must be checked");
return false;
}

// When checked option is a "Manual", additionaly validate a text
if (checkedOption.id == "optJustificationManual")
{
// Get min Justification length
var minJustificationLength = null;
inp = document.getElementById("MinJustificationLength");
if (inp != null && inp.value != null)
minJustificationLength = parseInt(inp.value, /* radix = */ 10);

// Get and validate "txtJustification" content
var txtJustification = document.getElementById("txtJustification");
if (txtJustification == null)
return true;
if (txtJustification.style.display == "none")
return true;

var text = txtJustification.value;
if (minJustificationLength == null)
{
if (text == null || text.replace(/^\s*/, "").replace(/\s*$/, "") == "")
{
MsgBoxError("Illegal empty justification");
txtJustification.focus();
return false;
}
}
else
{
if (text == null || text.length < minJustificationLength)
{
MsgBoxError("Justification must be at least " + minJustificationLength + " characters long.");
txtJustification.focus();
return false;
}
}
}

return true;
}
catch (ex)
{
return true;
}
}

function JsGetJustification()
{
/// <summary>
/// Returns string containing Justification.
/// </summary>

var text = "";

var visibleOptionExists = false;
var checkedOption = null;
var options = document.getElementsByName("optJustificationOption");
for (var i = 0; i < options.length; i++)
{
var opt = options[i];
if (opt == null)
continue;

if (opt.style.display == "none")
continue;

visibleOptionExists = true;

if (opt.checked)
{
checkedOption = opt; 
break;
}   
}

if (!visibleOptionExists)
{
// Even when no visible option exists, txtJustification itself can be visible.
var txtJustification = document.getElementById("txtJustification");
if (txtJustification == null || txtJustification.style.display == "none")
text = "";                // No visible option exists => justification should not be provided.
else
checkedOption = document.getElementById("optJustificationManual");
}

if (checkedOption != null)
{
if (checkedOption.id == "optJustificationManual")
{
var txtJustification = document.getElementById("txtJustification");
if (txtJustification != null)
text = txtJustification.value;
}
else
{
var id  = "lbl" + checkedOption.id.substring(3);
var lbl = document.getElementById(id);
if (lbl != null)
text = lbl.innerText;
}
}  

return text;
}

function InitJustificationTypeArea()
{
    try
    {
        if (JsIsFeatureEnabled("divJustificationTypeArea"))
        {
            var optTemporary = document.getElementById("optJustificationTypeTemporary");

            // Always default to Temporary option when feature is enabled
            if (optTemporary != null)
            {
                optTemporary.checked = true;
                var defaultValue = document.getElementById("DefaultJustificationHoursLimit");
                var txtTimeLimit = document.getElementById("txtJustificationTimeLimit");
                if (txtTimeLimit != null && defaultValue != null) {
                    txtTimeLimit.addEventListener('keypress', function (e) {
                        // prevent non-numeric input
                        if (!/\d/.test(e.key)) {
                            e.preventDefault();
                        }
                    });
                    txtTimeLimit.value = defaultValue.value;
                }
                onJustificationTypeClick("optJustificationTypeTemporary");
            }
        }
    }
    catch(ex) {}
}

function onJustificationTypeClick(optId)
{
    try
    {
        var opt = document.getElementById(optId);
        if (opt != null)
            opt.blur();

        var txtTimeLimit = document.getElementById("txtJustificationTimeLimit");

        if (optId == "optJustificationTypeTemporary")
        {
            if (txtTimeLimit != null)
            {
                txtTimeLimit.disabled = false;
                txtTimeLimit.focus();
            }
        }
        else if (optId == "optJustificationTypeOther")
        {
            if (txtTimeLimit != null)
                txtTimeLimit.disabled = true;
        }
    }
    catch(ex) { }
}

function JsGetJustificationType()
{
    var optTemporary = document.getElementById("optJustificationTypeTemporary");

    if (optTemporary != null && optTemporary.checked)
    {
        // Value for JIT Type
        return "1";
    }

    // Value for all other types
    return "2";
}

function validateJustificationType()
{
    if (!JsIsFeatureEnabled("divJustificationTypeArea"))
        return true;

    var optTemporary = document.getElementById("optJustificationTypeTemporary");
    var optOther = document.getElementById("optJustificationTypeOther");

    if ((optTemporary == null || !optTemporary.checked) && (optOther == null || !optOther.checked))
    {
        MsgBoxError("Please select a request type");
        return false;
    }

    if (optTemporary != null && optTemporary.checked)
    {
        var txtTimeLimit = document.getElementById("txtJustificationTimeLimit");
        if (txtTimeLimit != null && (txtTimeLimit.value == "" || txtTimeLimit.value < 1 || txtTimeLimit.value > 120))
        {
            MsgBoxError("Please specify a valid time limit between 1-120 hours");
            txtTimeLimit.focus();
            return false;
        }
    }

    return true;
}

function MsgBoxError(text)
{
try
{
if (external != null)
{
external.JsShowError(text);  
}
else
{
alert(text);
}
}
catch(ex)
{
alert(text);
} 
}

function RequestLanguage()
{
try
{
if (external != null)
{
var cultureId = external.JsGetLocaleName(); 
SetLanguage(cultureId);
}
}  
catch(ex)
{
}          
}

function SetLanguage(cultureId)
{
/// <summary>
/// Update content in order to show texts in given language (or most appropriated one).
/// </summary>

TraceInfo("SetLanguage: Dialog is requested to be displayed in '" + cultureId + "' language");

cultureId = ResolveLanguage(cultureId);

TraceInfo("SetLanguage: Dialog is going to be displayed in '" + cultureId + "' language");

var stringHolders = document.getElementsByTagName("input");
for (var i = 0; i < stringHolders.length; i++)
{
try
{
var stringHolder = stringHolders[i];

// Check whether stringHolder really contains translated string (should be hidden input with appropriated "lang")
if (stringHolder.type == null || stringHolder.type.toLowerCase() != "hidden")
continue;

if (stringHolder.lang == null || stringHolder.lang != cultureId)
continue; 

TraceStringHolder(stringHolder);

// Get the associated control
var ctrlId = stringHolder.getAttribute("ctrlid");
if (ctrlId == "DialogTitle")
{
// Special case: translation of Dialog Title
document.title = stringHolder.value;
}
else if (ctrlId == "AutorizationCodeRequest")
{
// Special case: translation of composite "AutorizationCodeRequest" control
var ctrl = document.getElementById("lblRequestId");
if (ctrl != null)
ctrl.innerHTML = stringHolder.value;

var ctrl = document.getElementById("lblFileId");
if (ctrl != null)
ctrl.innerHTML = stringHolder.value;
}
else
{
var ctrl = document.getElementById(ctrlId);
if (ctrl != null)
{
var tagName = ctrl.tagName.toLowerCase();

// Change associated control text
if (tagName == "span" || 
                        tagName == "h1"   || 
                        tagName == "h2"   ||
                        tagName == "a"    ||
                        tagName == "div"  ||
                        tagName == "button")
{
ctrl.innerHTML = stringHolder.value;  
}

else if (tagName == "input")
{
ctrl.value = stringHolder.value;        
}
}
}
}
catch(ex) { }
}
}

function TraceStringHolder(stringHolder)
{
if (stringHolder == null)
return;

var ctrlId = stringHolder.getAttribute("ctrlid");
ctrlId = (ctrlId != null) ? ctrlId : "Unknown Control";

var type = (stringHolder.type != null)  ? stringHolder.type  : "Unknown Type";
var lang = (stringHolder.lang != null)  ? stringHolder.lang  : "Unknown Language";
var translated = (stringHolder.value != null) ? stringHolder.value : "No translation";

TraceInfo("SetLanguage: StringHolder found: Control Id = '" + ctrlId + "'; type = '" + type + "'; language = '" + lang + "'; translated = '" + translated + "'.");
}

function ResolveLanguage(cultureId)
{
/// <summary>
/// Searches for most appropriated language defined for this dialog in following order:
/// Specific culture (ru-RU) -> Neutral culture (ru) -> Invariant culture (en).
/// </summary>

if (cultureId == "en")
return cultureId;

var defaultLanguage = GetDefaultLanguage();
TraceInfo("ResolveLanguage: defaultLanguage = " + defaultLanguage);

// Build list of languages defined for this dialog
var langs = new Array();
var elems = document.getElementsByName("Language");
if (elems == null)
return defaultLanguage;

var isEnglishPresented = false;

for (var i = 0; i < elems.length; i++)
{
var elem = elems[i];
var lang = elem.value;
langs.push(lang);
TraceInfo("ResolveLanguage: Language '" + lang + "' is defined.");

if (lang == "en")
isEnglishPresented = true;
}

if (!isEnglishPresented)
langs.push("en");  

// Search for requested language.
if (_searchLanguage(cultureId))
{
TraceInfo("ResolveLanguage: Requested Language '" + cultureId + "' is presented in list of defined Languages.");
return cultureId;
}

TraceInfo("ResolveLanguage: Requested Language '" + cultureId + "' is not presented in list of defined Languages.");

// Requested language is not found => search for parent languages (with respect to language id containing more than 2 parts).
var originalCultureId = cultureId;
var indexDash = -1;
while ((indexDash = cultureId.lastIndexOf('-')) > -1)
{
cultureId = cultureId.substring(0, indexDash);

TraceInfo("ResolveLanguage: Trying to find replacement Language '" + cultureId + "'.");

//if (cultureId != "en")  // When "en" is reached (for example, when "en-US" is resolved), default language should be returned. Otherwise default language will be ignored because "en" always is presented.
{
if (_searchLanguage(cultureId))
{
TraceInfo("ResolveLanguage: Replacement Language '" + cultureId + "' is presented in list of defined Languages.");
return cultureId;
}
}
}

// Special case: various Chinese language codes (EPM-3735; 2018/07/19)
// According to Microsoft:  zh-CN == zh-CHS == zh-Hans
//                          zh-HK == zh-CHT == zh-Hant
var chineseSimplified  = [ "zh-CN", "zh-CHS", "zh-Hans" ];
var chineseTraditional = [ "zh-HK", "zh-CHT", "zh-Hant" ];

if (chineseSimplified.indexOf(originalCultureId) > -1)
{
var replacementLangId = _findReplacement(chineseSimplified);
if (replacementLangId != null)
return replacementLangId;
}
else if (chineseTraditional.indexOf(originalCultureId) > -1)
{
var replacementLangId = _findReplacement(chineseTraditional);
if (replacementLangId != null)
return replacementLangId;
}

// Parent language is not found too => return language defined as default for this dialog.
return defaultLanguage;

function _searchLanguage(cultureId)
{
for (var i = 0; i < langs.length; i++)
{
if (cultureId == langs[i])
return true;
}

return false;
}

function _findReplacement(interchangeableLangs)
{
for (var j = 0; j < interchangeableLangs.length; j++)
{
var interchangeableLang = interchangeableLangs[j];

if (_searchLanguage(interchangeableLang))
return interchangeableLang;
}

return null;
}
}

function GetDefaultLanguage()
{
var inp = document.getElementById("DefaultLanguge");
if (inp != null)
return inp.value;
else
return "en";
}

function JsIsFeatureEnabled(id)
{
/// <summary>
/// Gets the boolean flag indicating whether feature is present and enabled.
/// </summary>
/// <param name="id" type="string">Feature id (for example: "divJustificationArea", "divPasswordArea").</param>
/// <returns>"True" when feature is present and enabled, otherwise "False" returned</returns>

var elem = document.getElementById(id);
if (elem == null)
return false;   // Feature is not present.

return (elem.style.display != "none");
}

function JsIsFeatureEnabledEx(id)
{
/// <summary>
/// Gets the boolean flag indicating whether feature is present and enabled.
/// </summary>
/// <param name="id" type="string">Feature id (for example: "divJustificationArea", "divPasswordArea").</param>
/// <returns>"True" when feature is present and enabled, otherwise "False" returned</returns>

var elem = document.getElementById(id);
if (elem == null)
return false;   // Feature is not present.

while (elem) 
{
if( typeof(elem.style) !== "undefined" &&
elem.style !== null && 
typeof(elem.style.display) !== "undefined" &&
elem.style.display !== null && 
elem.style.display === "none")
return false;
elem = elem.parentNode;
}

return true;
}

function JsEnableFeature(id, enable)
{
/// <summary>
/// Enables/disables (in fact show/hide) feature by given id.
/// </summary>
/// <param name="id" type="string">Feature id (for example: "divJustificationArea", "divPasswordArea").</param>
/// <param name="enable" type="bool">Flag to enable or disable feature.</param>
/// <returns>Nothing</returns>

if (enable && id == "divPinNoteArea")
return;     // This HTML element has special handling in JsSetFeatureValue function.

var elem = null;
if (typeof(id) == "string")
elem = document.getElementById(id);
else
elem = id;

if (elem != null)
{
if (elem.tagName.toLowerCase() == "br")
return;

elem.style.display = enable ? "block" : "none";

// Set visibility for all children
if (typeof(elem.children) != "undefined" && elem.children != null && typeof(elem.children.length) != "undefined")
{
for (var i = 0; i < elem.children.length; i++)
{
var child = elem.children[i];
if (child != null)
JsEnableFeature(child, enable);
}
}
}
}

function JsSetFeatureAccess(id, isAccessible)
{
/// <summary>
/// Change feature access (in fact enables/disables) by given id.
/// </summary>
/// <param name="id" type="string">Feature id (for example: "btnOK").</param>
/// <param name="isAccessible" type="bool">Flag to enable or disable feature.</param>
/// <returns>Nothing</returns>

var elem = null;
if (typeof(id) == "string")
elem = document.getElementById(id);
else
elem = id;

if (elem != null)
{
if (elem.tagName.toLowerCase() == "br")
return;

elem.disabled = !isAccessible;

// Set accessibility for all children
if (typeof(elem.children) != "undefined" && elem.children != null && typeof(elem.children.length) != "undefined")
{
for (var i = 0; i < elem.children.length; i++)
{
var child = elem.children[i];
if (child != null)
JsSetFeatureAccess(child, isAccessible);
}
}
}
}

function JsGetFeatureValue(id)
{
/// <summary>
/// Gets the value of feature by given id.
/// </summary>
/// <param name="id" type="string">Feature id (for example: "divJustificationArea", "divPasswordArea", "divEmailArea").</param>
/// <returns>Value as string</returns>
/// <remarks>JsIsFeatureEnabled must be called before JsGetFeatureValue</remarks>

var txt = null;
var chk = null;

switch (id)
{
case "divJustificationArea":
return JsGetJustification();

        case "optJustificationType":
            return JsGetJustificationType();

        case "txtJustificationTimeLimit":
            var justificationType = JsGetJustificationType();
            if (justificationType != "1")
                return "";
            txt = document.getElementById("txtJustificationTimeLimit");
            return (txt != null) ? txt.value : "";

case "UserAuthenticationOption":
txt = document.getElementById("UserAuthenticationOption");
return (txt != null) ? txt.value : "";            

case "divUserNameArea":
txt = document.getElementById("txtUserName");
if (txt != null && txt.style.display != "none") 
return txt.value;

txt = document.getElementById("lblUserName");   // Some of dialogs use labels (span) as User Name holder.
if (txt != null && txt.style.display != "none")
return txt.innerText;

return "";

case "divPasswordArea": 
case "divPasswordContentArea":
txt = document.getElementById("txtPassword");
return (txt != null) ? txt.value : "";

case "divPinArea":      
txt = document.getElementById("txtPin");
return (txt != null) ? txt.value : "";

case "divEmailArea":
txt = document.getElementById("txtEmail");
return (txt != null) ? txt.value : "";

case "divAutorizationCodeArea":
txt = document.getElementById("txtAutorizationCode");
return (txt != null) ? txt.value : "";

case "divPolicyAutoResumeArea":
chk = document.getElementById("chkPolicyAutoResume");
return (chk != null) ? (chk.checked ? "true" : "false") : "true";     // "true" is a default value according to TSK-1423.
}

return "";
}

function JsSetFeatureValue(id, value)
{
/// <summary>
/// Sets the value of feature by given id.
/// </summary>
/// <param name="id" type="string">Feature id (for example: "divPinNoteArea").</param>
/// <param name="value" type="string">Value as string</param>
/// <returns>Nothing.</returns>

var isValueDefined = (value != null && value != "");

switch (id)
{
case "divPinArea":      
{
var txt = document.getElementById("txtPin");
if (txt != null) 
txt.value = isValueDefined ? value : "";
}
break;

case "divPasswordArea": 
case "divPasswordContentArea":
{
var txt = document.getElementById("txtPassword");
if (txt != null) 
txt.value = isValueDefined ? value : "";
}
break;

case "divPinNoteArea":
{
var divArea = document.getElementById("divPinNoteArea");
if (divArea != null)
divArea.style.display = isValueDefined ? "" : "none";   // Not "block", because "colspan" is broken when <tr> has a style "display:block".

lbl = document.getElementById("lblPinNote");
if (lbl != null)
{
lbl.innerHTML     = value;
lbl.style.display = isValueDefined ? "" : "none";    
}

SetFeatureValueTranslations(id, value);
}
break;

case "divAutorizationCodeArea":
{
var txt = document.getElementById("txtAutorizationCode");
if (txt != null) 
txt.value = isValueDefined ? value : "";
}
break;

case "lblStepUpAuthentication":
{
var lbl = document.getElementById("lblStepUpAuthentication");
if (lbl != null) 
lbl.innerHTML = isValueDefined ? value : "";

SetFeatureValueTranslations(id, value);
}
break;

case "lblStepUpAuthorization":
{
var lbl = document.getElementById("lblStepUpAuthorization");
if (lbl != null)
lbl.innerHTML = isValueDefined ? value : "";

SetFeatureValueTranslations(id, value);
}
break;
}
}

function SetFeatureValueTranslations(id, value)
{
/// <summary>
/// Propagates the value of feature by given id to all translations
/// (need to fix Agent bug EPM-29732; 2023/07/05)
/// </summary>

var translationHolders = document.getElementsByTagName("input");
for (var i = 0; i < translationHolders.length; i++)
{
try
{
var translationHolder = translationHolders[i];

// Check whether translationHolder really contains translated string (should be hidden input)
if (translationHolder.type == null || translationHolder.type.toLowerCase() != "hidden")
continue;

var ctrlId = translationHolder.getAttribute("ctrlid");
if (ctrlId == id)
{
translationHolder.value = value;
}
}
catch(ex) { }
}
}

