width: 300px; /* works instead of max-width to support WebBrowser control emulating IE7 */
}

p {
margin: 0px;
}

/* Styles to ensure wrapping of very long strings in the lblInfo1Value, lblInfo2Value, lblInfo3Value areas (EPM-7279; 2020/07/19) */
